import { useState } from "react";

const COMMANDS = [
  { icon: "⚡", label: "Neues Projekt erstellen", shortcut: "N" },
  { icon: "👥", label: "Teammitglied einladen", shortcut: "I" },
  { icon: "📊", label: "Analytics öffnen", shortcut: "A" },
  { icon: "⚙️", label: "Einstellungen", shortcut: "S" },
  { icon: "📝", label: "Dokumentation", shortcut: "D" },
  { icon: "🔍", label: "Globale Suche", shortcut: "/" },
];

export default function ModalCommandPalette01() {
  const [query, setQuery] = useState("");
  const filtered = COMMANDS.filter((c) =>
    c.label.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <div className="mx-auto w-full max-w-lg overflow-hidden rounded-2xl border border-white/10 bg-slate-900 shadow-2xl">
      <div className="flex items-center gap-3 border-b border-white/10 px-4 py-3">
        <span className="text-slate-400">🔍</span>
        <input
          className="flex-1 bg-transparent text-sm text-white placeholder-slate-500 outline-none"

          value={query}
          onChange={(e) => setQuery(e.target.value)}
          autoFocus
        />
        <kbd className="rounded border border-white/10 px-1.5 py-0.5 text-[10px] text-slate-400">ESC</kbd>
      </div>
      <div className="py-2">
        {filtered.length === 0 ? (
          <p className="px-4 py-6 text-center text-sm text-slate-500">Keine Ergebnisse für „{query}"</p>
        ) : (
          filtered.map((cmd, i) => (
            <button
              key={cmd.label}
              className={`flex w-full items-center gap-3 px-4 py-2.5 text-left text-sm transition ${i === 0 ? "bg-violet-600/20 text-violet-100" : "text-slate-300 hover:bg-white/5"}`}
            >
              <span className="text-base">{cmd.icon}</span>
              <span className="flex-1">{cmd.label}</span>
              <kbd className="rounded border border-white/10 px-1.5 py-0.5 text-[10px] text-slate-500">{cmd.shortcut}</kbd>
            </button>
          ))
        )}
      </div>
      <div className="border-t border-white/5 px-4 py-2 flex gap-4 text-[10px] text-slate-600">
        <span>↑↓ Navigieren</span>
        <span>↵ Ausführen</span>
        <span>ESC Schließen</span>
      </div>
    </div>
  );
}

